arguments.file_text:
@using sv_61bae615066f4efc95904da398e041ed.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    <div class="section-header">
        <h3>Profile</h3>
        <p>Manage your personal information</p>
    </div>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="avatar-area mb-4">
            <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
            <div class="avatar-url-display">
                <label class="form-label fw-semibold">Avatar URL</label>
                <input type="url" class="form-control form-control-sm" value="@_avatarUrl" readonly />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Display Name</label>
            <input type="text" class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label fw-semibold">Bio</label>
            <textarea class="form-control" rows="3" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardChanges" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    }

    @if (_toastMessage is not null)
    {
        <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
            @_toastMessage
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    // Snapshot for discard
    private UserProfile? _savedProfile;

    private string? _toastMessage;
    private bool _toastIsError;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        ApplyProfile(profile);
        _savedProfile = profile;
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _avatarUrl = p.AvatarUrl;
        _bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            await ShowToast("Profile saved successfully!");
        }
        catch
        {
            await ShowToast("Failed to save profile.", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
            ApplyProfile(_savedProfile);
    }

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

.profile-section .avatar-area {
    display: flex;
    align-items: center;
    gap: 1.25rem;
}

.profile-section .avatar-preview {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.profile-section .avatar-url-display {
    flex: 1;
}

@using sv_61bae615066f4efc95904da398e041ed.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    <div class="section-header">
        <h3>Notifications</h3>
        <p>Control how and when you receive notifications</p>
    </div>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="form-section">
            <h6 class="fw-semibold mb-3">Notification Channels</h6>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Email Notifications</div>
                    <div class="toggle-description">Receive updates via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_emailNotifications" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Push Notifications</div>
                    <div class="toggle-description">Get real-time push alerts</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_pushNotifications" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Weekly Digest</div>
                    <div class="toggle-description">Summary of activity sent every Monday</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_weeklyDigest" />
                </div>
            </div>
        </div>

        <div class="form-section">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            <p class="text-muted small">Select channels to mute notifications from</p>

            @foreach (var channel in _allChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="(e) => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }

    @if (_toastMessage is not null)
    {
        <div class="toast-message toast-success">@_toastMessage</div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];
    private string? _toastMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];

        // Get all channels from the mock service
        if (SettingsService is MockSettingsService mock)
            _allChannels = mock.GetAllChannels();
        else
            _allChannels = [.. _mutedChannels]; // fallback

        _loading = false;
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var prefs = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest,
            [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;

        _toastMessage = "Notification preferences saved!";
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

@using sv_61bae615066f4efc95904da398e041ed.Services
@inject ISettingsService SettingsService

<div class="security-section">
    <div class="section-header">
        <h3>Security</h3>
        <p>Manage your password, two-factor authentication, and sessions</p>
    </div>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <!-- Change Password -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span>@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="form-section">
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Two-Factor Authentication</div>
                    <div class="toggle-description">
                        @if (_twoFactorEnabled)
                        {
