@inject ISettingsService SettingsService

<div class="notifications-section">
    <div class="section-header">
        <h3>Notifications</h3>
        <p>Control how and when you receive notifications</p>
    </div>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="form-section">
            <h6 class="fw-semibold mb-3">Notification Channels</h6>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Email Notifications</div>
                    <div class="toggle-description">Receive updates via email</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_emailNotifications" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Push Notifications</div>
                    <div class="toggle-description">Get real-time push alerts</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_pushNotifications" />
                </div>
            </div>

            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Weekly Digest</div>
                    <div class="toggle-description">Summary of activity sent every Monday</div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_weeklyDigest" />
                </div>
            </div>
        </div>

        <div class="form-section">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            <p class="text-muted small">Select channels to mute notifications from</p>

            @foreach (var channel in _allChannels)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="(e) => ToggleMutedChannel(channel, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    }

    @if (_toastMessage is not null)
    {
        <div class="toast-message toast-success">@_toastMessage</div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];
    private string? _toastMessage;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];

        // Get all channels from the mock service
        if (SettingsService is MockSettingsService mock)
            _allChannels = mock.GetAllChannels();
        else
            _allChannels = [.. _mutedChannels]; // fallback

        _loading = false;
    }

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var prefs = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest,
            [.. _mutedChannels]);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;

        _toastMessage = "Notification preferences saved!";
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

