@using sv_61bae615066f4efc95904da398e041ed.Services
@inject ISettingsService SettingsService

<div class="security-section">
    <div class="section-header">
        <h3>Security</h3>
        <p>Manage your password, two-factor authentication, and sessions</p>
    </div>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <!-- Change Password -->
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <span class="fw-semibold">Change Password</span>
                <span>@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="form-section">
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Two-Factor Authentication</div>
                    <div class="toggle-description">
                        @if (_twoFactorEnabled)
                        {
                            <span class="badge bg-success me-1">Enabled</span>
                        }
                        else
                        {
                            <span class="badge bg-secondary me-1">Disabled</span>
                        }
                        Add an extra layer of security to your account
                    </div>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           @bind="_twoFactorEnabled" />
                </div>
            </div>

            @if (_lastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")
                </p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="form-section mt-4">
            <h6 class="fw-semibold mb-3">Active Sessions</h6>
            <div class="table-responsive">
                <table class="table table-hover align-middle">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@FormatLastActive(session.LastActive)</td>
                                <td class="text-end">
                                    @if (session.Id != _currentSessionId)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-primary">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>
    }

    <!-- Revoke Confirmation Dialog -->
    @if (_sessionToRevoke is not null)
    {
        <div class="confirmation-overlay" @onclick="CancelRevoke">
            <div class="confirmation-dialog" @onclick:stopPropagation>
                <h5>Revoke Session</h5>
                <p>
                    Are you sure you want to revoke the session on
                    <strong>@_sessionToRevoke.Device</strong>
                    from <strong>@_sessionToRevoke.Location</strong>?
                </p>
                <p class="text-muted small">This will sign out the device immediately.</p>
                <div class="d-flex justify-content-end gap-2">
                    <button class="btn btn-outline-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                </div>
            </div>
        </div>
    }

    @if (_toastMessage is not null)
    {
        <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
            @_toastMessage
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _passwordExpanded;
    private bool _changingPassword;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string _currentSessionId = "sess-1"; // First session is "current"

    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;

    private ActiveSession? _sessionToRevoke;
    private string? _toastMessage;
    private bool _toastIsError;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = [.. settings.Sessions];
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _lastPasswordChange = DateTime.UtcNow;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        _passwordExpanded = false;

        await ShowToast("Password updated successfully!");
    }

    private void PromptRevoke(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
        _sessionToRevoke = null;

        await ShowToast("Session revoked.");
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

