@using sv_61bae615066f4efc95904da398e041ed.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    <div class="section-header">
        <h3>Appearance</h3>
        <p>Customize the look and feel of the application</p>
    </div>

    @if (_loading)
    {
        <div class="text-center py-4">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-6">
                <!-- Theme -->
                <div class="form-section">
                    <h6 class="fw-semibold mb-3">Theme</h6>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <!-- Font Size -->
                <div class="form-section">
                    <h6 class="fw-semibold mb-3">Font Size</h6>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"size-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"size-{size}")">@size</label>
                        </div>
                    }
                </div>

                <!-- Language -->
                <div class="form-section">
                    <h6 class="fw-semibold mb-3">Language</h6>
                    <select class="form-select" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="form-section">
                    <div class="toggle-row">
                        <div>
                            <div class="toggle-label">Compact Mode</div>
                            <div class="toggle-description">Reduce spacing and padding throughout the UI</div>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   @bind="_compactMode" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary mt-2" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>
            </div>

            <!-- Live Preview -->
            <div class="col-md-6">
                <div class="preview-panel @GetPreviewClasses()">
                    <h6 class="preview-title">Live Preview</h6>
                    <div class="preview-card">
                        <div class="preview-header">Dashboard</div>
                        <p class="preview-text">
                            This is how your content will look with the selected settings.
                        </p>
                        <div class="d-flex gap-2 mb-2">
                            <span class="badge bg-primary">Label</span>
                            <span class="badge bg-success">Active</span>
                            <span class="badge bg-warning text-dark">Pending</span>
                        </div>
                        <button class="btn btn-sm btn-primary">Sample Button</button>
                    </div>
                    <div class="preview-meta">
                        Theme: @_theme · Font: @_fontSize · Compact: @(_compactMode ? "On" : "Off")
                    </div>
                </div>
            </div>
        </div>
    }

    @if (_toastMessage is not null)
    {
        <div class="toast-message toast-success">@_toastMessage</div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private string? _toastMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            _ => "preview-light"
        });
        classes.Add(_fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;

        _toastMessage = "Appearance settings saved!";
        StateHasChanged();
        await Task.Delay(3000);
        _toastMessage = null;
    }
}

.preview-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.25rem;
    transition: all 0.3s ease;
}

.preview-title {
    font-weight: 600;
    margin-bottom: 1rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid currentColor;
    opacity: 0.3;
}

.preview-card {
    padding: 1rem;
    border-radius: 0.375rem;
    border: 1px solid rgba(0, 0, 0, 0.1);
    margin-bottom: 1rem;
}

.preview-header {
    font-weight: 600;
    margin-bottom: 0.5rem;
}

.preview-meta {
    font-size: 0.8rem;
    opacity: 0.6;
}

/* Theme variants */
.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-light .preview-card {
    background: #f8f9fa;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .preview-card {
    background: #313244;
    border-color: rgba(255, 255, 255, 0.1);
}

/* Font size variants */
.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.15rem;
}

/* Compact mode */
.preview-compact {
    padding: 0.75rem;
}

.preview-compact .preview-card {
    padding: 0.5rem;
    margin-bottom: 0.5rem;
}

.preview-compact .preview-title {
    margin-bottom: 0.5rem;
    padding-bottom: 0.25rem;
}

